#!/usr/bin/env bash
# topic-4.sh — 孩子 决策助手 for 家庭教育指导.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 2 (Playbook).
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="家庭教育指导"
TOPIC="孩子"

usage() {
  cat <<EOF
topic-4.sh — ${TOPIC} 决策助手 for ${INDUSTRY}

基于 3 条 playbook 规则的交互式决策评估。
你描述情景, 工具帮你判断哪条规则适用, 并给推荐。

USAGE:
  ./topic-4.sh             # interactive
  ./topic-4.sh --dry-run   # walk through but no file
  ./topic-4.sh --json      # JSON to stdout
  ./topic-4.sh --explain   # show backing playbook rules + mental models
  ./topic-4.sh --help      # this message
EOF
}

explain() {
  cat <<'EOT'
这个决策助手把 孩子 主题下的 playbook 规则组合成交互树。

基于 3 条规则:
  • 如果 家长问「正面管教是不是不能惩罚孩子」 → 则 : 则纠正这个最常见的误读 — 正面管教反对的是「惩罚」(让孩子受苦来学教训), 不反对「界限」和「后果」
  • 如果 接到离异家庭共同养育个案 → 则 : 则以「孩子最佳利益」为唯一框架, 不站任何一方 — 分别会见离异双方, 评估孩子的忠诚冲突信号 (在两边说不同的话/
  • 如果 家长来咨询手机/网络沉迷问题 → 则 : 则第一步评估的不是孩子的手机使用时间, 而是亲子关系状态和孩子的线下需求满足程度 — SDT 自我决定理论的三需求 

相关心智模型:
  • 关系先于教育 (Connection Before Correction): 家庭教育指导的第一原则不是「教家长正确做法」, 而是先修复或巩固亲子情感连接 — 没有安全依恋基础的教养技术是空中楼阁, Bowlby/Ainsworth 的依恋理论和 Siegel 的「连接先于纠正
  • 行为是信号, 不是问题本身 (Behavior Is a Signal, Not the Problem): 孩子的「问题行为」(发脾气/撒谎/拒学/手机沉迷) 几乎从来不是问题本身, 而是未被满足的需求在呐喊 — Dreikurs 的四个错误目标 (寻求关注/争夺权力/报复/自我放弃) 和 Rosenber

来源: synthesis.md Section 2.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "家长问「正面管教是不是不能惩罚孩子」"
  "接到离异家庭共同养育个案"
  "家长来咨询手机/网络沉迷问题"
)
declare -a RULE_ACTIONS=(
  ": 则纠正这个最常见的误读 — 正面管教反对的是「惩罚」(让孩子受苦来学教训), 不反对「界限」和「后果」"
  ": 则以「孩子最佳利益」为唯一框架, 不站任何一方 — 分别会见离异双方, 评估孩子的忠诚冲突信号 (在两边说不同的话/用一方贬低另一方来讨好当前在场方); 帮助双方制定书面共同养育协议 (时间安排/重大决策通知规则/禁止在孩子面前贬低对方)"
  ": 则第一步评估的不是孩子的手机使用时间, 而是亲子关系状态和孩子的线下需求满足程度 — SDT 自我决定理论的三需求 (自主/胜任/关系) 如果在现实中持续受挫, 孩子会在虚拟世界寻找替代满足"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
if [[ ${#APPLIED_RULES[@]} -eq 0 ]]; then
  ms_buffer_append "(无适用 playbook 规则 — 此情景在已知 OS 之外, 建议回到 SKILL.md 心智模型层重新分析)"
else
  for ridx in "${APPLIED_RULES[@]}"; do
    i=$((ridx-1))
    ms_buffer_append "- **情景**: ${RULE_CONDITIONS[$i]} → **做法**: ${RULE_ACTIONS[$i]}"
  done
fi
ms_buffer_append ""

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "topic" "${TOPIC}" \
    "situation" "${SITUATION}" \
    "applied_rules_count" "${#APPLIED_RULES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "topic-4-decision"
fi
